sql:
SELECT security_id, security_name, security_type, issue_date, maturity_date
FROM securities
LIMIT 5;

SELECT security_id, security_name, security_type, isin, issuer_id
FROM securities
ORDER BY security_name ASC;

external_knowledge:
- "seasoned navigators" refers to users with the role of 'trader';
- "individual sails" refers to the 'individual' type of trading accounts;
- "successful voyages" refers to trades with the status of 'executed';
- "treasure" represents the total value traded calculated as the sum of quantity multiplied by trade price;
- "richness of their maritime endeavors" means the total trades, sorted in descending order.

sql:
SELECT AVG(close_price) AS average_close_price
FROM market_data
WHERE date BETWEEN date('now', '-30 days') AND date('now');

SELECT date, close_price
FROM market_data
ORDER BY date DESC;

SELECT COUNT(security_id) AS number_of_securities
FROM securities
WHERE security_type = 'stock';

SELECT AVG(close_price) AS average_close_price
FROM market_data
WHERE date = '2023-04-01' AND high_price > (SELECT AVG(high_price) FROM market_data WHERE date = '2023-04-01');
